// Split into batches of 20 rows for Claude context economy.
const rows = Array.isArray($input.item.json) ? $input.item.json : [];
const BATCH = 20;
const out = [];
for (let i = 0; i < rows.length; i += BATCH) {
  out.push({ json: { batch: rows.slice(i, i + BATCH) } });
}
return out;

const batch = $input.item.json.batch || [];
const system_prompt = [
  'You are Crystallux Productivity Classifier.',
  'Classify each activity as "productive", "neutral", or "unproductive".',
  'Output STRICT JSON array of the same length, same order, each element: { id, classification }.',
  'Rules:',
  ' - Productive: outreach_sent under 10 min, call_made 2-45 min, meeting_held 15-60 min, lead_qualified, deal_closed, follow_up_sent.',
  ' - Neutral: dashboard_session under 30 min, manual_note.',
  ' - Unproductive: idle over 15 min, dashboard_session over 60 min without other activity, repeat of same activity within 5 min.',
  ' - Default to "neutral" if uncertain; never output anything other than the three labels.'
].join('\n');
const user_prompt = 'Activities (JSON):\n' + JSON.stringify(batch, null, 2) + '\n\nReturn the JSON array now.';
return { json: { batch, system_prompt, user_prompt } };

const resp = $input.item.json || {};
const prep = $('Prep Prompt').first().json;
const batch = prep.batch || [];

let parsed = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  if (text.trim().length > 0) parsed = JSON.parse(text.trim());
} catch (e) { parsed = null; }

if (!Array.isArray(parsed)) {
  // Fallback: mark neutral so we don't loop on the same rows forever.
  parsed = batch.map(function(b) { return { id: b.id, classification: 'neutral' }; });
}

// Normalise + clamp
parsed = parsed.map(function(p) {
  let c = String((p && p.classification) || 'neutral').toLowerCase();
  if (['productive','neutral','unproductive'].indexOf(c) === -1) c = 'neutral';
  return { id: p.id, classification: c };
});

return { json: { results: parsed } };

// Explode the batch into per-row PATCH items so the next HTTP node
// runs once per activity.
const rows = $input.item.json.results || [];
return rows.map(function(r) { return { json: r }; });
